item.description:
LeetCode版本 如果只是刷LeetCode的话,可以看看我以前写的版本.这个能过LeetCode,但是实际上存在严重的代码问题,使用了被move的元素.
实用版本 这个版本解决了上面的问题,同时用模板让元素类型可以自定义.
#include &lt;list&gt;#include &lt;mutex&gt;#include &lt;unordered_map&gt; template &lt;typename Key, typename Value&gt; class LRUCache { typedef std::list&lt;std::pair&lt;Key, Value&gt;&gt; lru_list; typedef std::unordered_map&lt;Key, typename lru_list::iterator&gt; lru_map; private: lru_list lru_list_; lru_map lru_map_; size_t lru_capacity_ = 1; std::mutex lru_lock_; public: int Get(const Key &amp;key, Value &amp;value) { std::lock_guard&lt;std::mutex&gt; lock(lru_lock_); typename lru_map::iterator lru_map_it = lru_map_.find(key); if (lru_map_it == lru_map_.end()) return -ESRCH; std::pair&lt;Key, Value&gt; lru_element = *(lru_map_it-&gt;second); value = lru_element.second; lru_list_.erase(lru_map_it-&gt;second); lru_list_.push_front(move(lru_element)); lru_map_[key] = lru_list_.begin(); return 0; } int Put(const Key &amp;key, const Value &amp;value) { std::lock_guard&lt;std::mutex&gt; lock(lru_lock_); typename lru_map::iterator lru_map_it = lru_map_.
